# morphological naive stems: remove prefixes like 'ل' 'و' 'ال' from each token
orig_tokens = ["انك","تحمل","الكتاب","تكتب","تعلم","تقول"]
def stem(token):
    t = token
    if t.startswith('ال'):
        t = t[2:]
    if t.startswith('و'):
        t = t[1:]
    if t.startswith('ل'):
        t = t[1:]
    return t

stems = [stem(normalize(t)) for t in orig_tokens]
stems

